import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;

/**
 * Kafka consumer that processes inventory update messages idempotently.
 * Follows ecosystem patterns:
 * - Uses ConsumerConfig constants for all configuration
 * - Uses poll(Duration) API for fetching records
 * - Uses commitSync() for synchronous offset commits
 * - Handles WakeupException for clean shutdown
 */
public class InventoryConsumer {
    private final KafkaConsumer<String, String> consumer;
    private final String topic = "inventory-updates";
    private volatile boolean closed = false;

    public InventoryConsumer(String bootstrapServers, String groupId) {
        Properties props = new Properties();

        // Use ConsumerConfig constants (not string literals)
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        this.consumer = new KafkaConsumer<>(props);
    }

    /**
     * Main consumer loop that processes messages from the inventory-updates topic.
     * Implements idempotent processing through:
     * - Committing offsets only after successful processing
     * - Using manual commit (enable.auto.commit=false)
     * - Processing records in batches
     */
    public void run() {
        try {
            consumer.subscribe(Collections.singletonList(topic));

            while (!closed) {
                // Use poll(Duration) API (not deprecated poll(long))
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));

                if (!records.isEmpty()) {
                    // Process batch of records
                    for (ConsumerRecord<String, String> record : records) {
                        processRecord(record);
                    }

                    // Commit offsets after processing each batch
                    // This ensures idempotent processing - if processing fails,
                    // offsets won't be committed and records will be reprocessed
                    consumer.commitSync();
                }
            }
        } catch (WakeupException e) {
            // Handle WakeupException for clean shutdown
            if (!closed) {
                throw e;
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Process a single inventory update record.
     * This is where idempotent business logic would be implemented.
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        // Example: Parse and process inventory update
        String inventoryId = record.key();
        String updateData = record.value();

        // Idempotent processing: implementation should use the offset/key combination
        // to detect and skip duplicates (e.g., via database uniqueness constraint)
        System.out.printf("Processing inventory update - ID: %s, Data: %s, Offset: %d%n",
                inventoryId, updateData, record.offset());
    }

    /**
     * Shutdown the consumer gracefully by triggering a wakeup.
     */
    public void shutdown() {
        closed = true;
        consumer.wakeup();
    }

    public static void main(String[] args) {
        String bootstrapServers = args.length > 0 ? args[0] : "localhost:9092";
        String groupId = args.length > 1 ? args[1] : "inventory-consumer-group";

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers, groupId);

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(inventoryConsumer::shutdown));

        inventoryConsumer.run();
    }
}

